+// ─── Centralized Color Palette System ─────────────────────────────
+
+type WallDecorationType = 'banner' | 'shield' | 'weaponDisplay' | 'painting' | 'sconce';
+
+const CASTLE_PALETTE = {
+  stone: ['#1e1e2a', '#2d2d3d', '#3f3f52', '#555568', '#6e6e82'],
+  wood: ['#1a0e06', '#2e1a0a', '#3e2a18', '#5c3317', '#7a5030'],
+  metal: ['#4a4a58', '#6a6a78', '#8a8a98', '#b0b0c0', '#d0d0e0'],
+  fabric: ['#7a1010', '#8b1515', '#a02525', '#c03030', '#e04040'],
+  nature: ['#2a6a2a', '#40b040', '#3a6b35', '#2a4b25', '#1a3a10'],
+  gold: ['#806020', '#b08830', '#d4a840', '#f0c040', '#fff080'],
+};
+
+function drawBannerDecoration(ctx: CanvasRenderingContext2D, x: number, y: number, scale: number) {
+  drawBanner(ctx, x, y, 16 * scale, 32 * scale, CASTLE_PALETTE.fabric[1], CASTLE_PALETTE.gold[3]);
+}
+
+function drawShieldDecoration(ctx: CanvasRenderingContext2D, x: number, y: number, scale: number) {
+  ctx.save();
+  ctx.translate(x, y);
+  ctx.scale(scale, scale);
+  ctx.fillStyle = CASTLE_PALETTE.gold[3];
+  ctx.beginPath();
+  ctx.moveTo(8, 0);
+  ctx.lineTo(16, 12);
+  ctx.lineTo(12, 24);
+  ctx.lineTo(4, 24);
+  ctx.lineTo(0, 12);
+  ctx.closePath();
+  ctx.fill();
+  ctx.fillStyle = CASTLE_PALETTE.fabric[3];
+  ctx.beginPath();
+  ctx.moveTo(8, 3);
+  ctx.lineTo(14, 12);
+  ctx.lineTo(10, 21);
+  ctx.lineTo(6, 21);
+  ctx.lineTo(2, 12);
+  ctx.closePath();
+  ctx.fill();
+  ctx.restore();
+}
+
+function drawWeaponDisplayDecoration(ctx: CanvasRenderingContext2D, x: number, y: number, scale: number) {
+  ctx.save();
+  ctx.translate(x, y);
+  ctx.scale(scale, scale);
+  ctx.fillStyle = CASTLE_PALETTE.wood[3];
+  ctx.fillRect(0, 0, 20, 28);
+  ctx.strokeStyle = CASTLE_PALETTE.wood[2];
+  ctx.lineWidth = 1;
+  for (let i = 3; i < 18; i += 7) {
+    ctx.beginPath();
+    ctx.moveTo(i, 4);
+    ctx.lineTo(i, 24);
+    ctx.stroke();
+  }
+  ctx.strokeStyle = CASTLE_PALETTE.metal[2];
+  ctx.lineWidth = 2;
+  ctx.beginPath();
+  ctx.moveTo(6, 6);
+  ctx.lineTo(6, 22);
+  ctx.stroke();
+  ctx.fillStyle = CASTLE_PALETTE.metal[1];
+  ctx.fillRect(3, 5, 6, 2);
+  ctx.fillRect(5, 22, 2, 3);
+  ctx.beginPath();
+  ctx.moveTo(14, 6);
+  ctx.lineTo(14, 22);
+  ctx.stroke();
+  ctx.fillStyle = CASTLE_PALETTE.metal[1];
+  ctx.fillRect(11, 5, 6, 2);
+  ctx.fillRect(13, 22, 2, 3);
+  ctx.restore();
+}
+
+function drawPaintingDecoration(ctx: CanvasRenderingContext2D, x: number, y: number, scale: number) {
+  ctx.save();
+  ctx.translate(x, y);
+  ctx.scale(scale, scale);
+  ctx.fillStyle = CASTLE_PALETTE.wood[3];
+  ctx.fillRect(0, 0, 24, 18);
+  ctx.fillStyle = CASTLE_PALETTE.wood[2];
+  ctx.fillRect(2, 2, 20, 14);
+  const grad = ctx.createLinearGradient(2, 2, 22, 16);
+  grad.addColorStop(0, CASTLE_PALETTE.nature[0]);
+  grad.addColorStop(0.5, CASTLE_PALETTE.nature[1]);
+  grad.addColorStop(1, CASTLE_PALETTE.nature[0]);
+  ctx.fillStyle = grad;
+  ctx.fillRect(2, 2, 20, 14);
+  ctx.fillStyle = CASTLE_PALETTE.gold[4];
+  ctx.beginPath();
+  ctx.arc(18, 6, 3, 0, Math.PI * 2);
+  ctx.fill();
+  ctx.restore();
+}
+
+function drawSconceDecoration(ctx: CanvasRenderingContext2D, x: number, y: number, scale: number, frame: number) {
+  ctx.save();
+  ctx.translate(x, y);
+  ctx.scale(scale, scale);
+  ctx.fillStyle = CASTLE_PALETTE.wood[3];
+  ctx.fillRect(6, 8, 4, 12);
+  ctx.fillStyle = CASTLE_PALETTE.wood[4];
+  ctx.fillRect(7, 9, 2, 10);
+  ctx.fillStyle = CASTLE_PALETTE.metal[0];
+  ctx.fillRect(5, 6, 6, 4);
+  ctx.fillRect(7, 4, 2, 4);
+  const flicker = TORCH_FLAME_OFFSETS[frame % TORCH_FLAME_OFFSETS.length];
+  const fx = 8 + flicker.dx;
+  const fy = 4 + flicker.dy;
+  const flameRadius = 6;
+  const flameGradient = ctx.createRadialGradient(fx, fy, 0, fx, fy, flameRadius);
+  flameGradient.addColorStop(0, 'rgba(255, 180, 60, 0.8)');
+  flameGradient.addColorStop(0.5, 'rgba(255, 140, 20, 0.4)');
+  flameGradient.addColorStop(1, 'rgba(255, 80, 0, 0)');
+  ctx.fillStyle = flameGradient;
+  ctx.beginPath();
+  ctx.ellipse(fx, fy, flameRadius, flameRadius * 1.5, 0, 0, Math.PI * 2);
+  ctx.fill();
+  ctx.fillStyle = 'rgba(255, 255, 180, 0.9)';
+  ctx.beginPath();
+  ctx.ellipse(fx, fy, flameRadius * 0.5, flameRadius * 0.75, 0, 0, Math.PI * 2);
+  ctx.fill();
+  ctx.restore();
+}
+
+export function drawWallDecoration(
+  ctx: CanvasRenderingContext2D,
+  type: WallDecorationType,
+  x: number,
+  y: number,
+  scale: number,
+  frame: number = 0,
+) {
+  switch (type) {
+    case 'banner': drawBannerDecoration(ctx, x, y, scale); break;
+    case 'shield': drawShieldDecoration(ctx, x, y, scale); break;
+    case 'weaponDisplay': drawWeaponDisplayDecoration(ctx, x, y, scale); break;
+    case 'painting': drawPaintingDecoration(ctx, x, y, scale); break;
+    case 'sconce': drawSconceDecoration(ctx, x, y, scale, frame); break;
+  }
+}
+
